import subprocess
import time

def run_with_retry(cmd: list, max_retries: int = 3, base_delay: float = 2.0) -> bool:
    for attempt in range(max_retries + 1):
        result = subprocess.run(cmd)
        if result.returncode == 0:
            return True
        if attempt < max_retries:
            delay = base_delay * (2 ** attempt)
            print(f'Attempt {attempt + 1} failed. Retrying in {delay:.1f}s...')
            time.sleep(delay)
        else:
            print(f'Command failed after {max_retries + 1} attempts.')
    return False

import subprocess

def get_affected_services(services: list, base_branch: str = 'main') -> list:
    try:
        result = subprocess.run(
            ['git', 'diff', '--name-only', f'{base_branch}...HEAD'],
            capture_output=True,
            text=True,
            check=True
        )
    except subprocess.CalledProcessError:
        # If git diff fails (e.g. base branch not found), return all services
        return list(services)

    changed_files = [line.strip() for line in result.stdout.splitlines() if line.strip()]
    affected = []
    for service in services:
        prefix = service.rstrip('/') + '/'
        if any(f.startswith(prefix) or f == service for f in changed_files):
            affected.append(service)
    return affected

import time
import requests

def wait_for_healthy(health_url: str, timeout_seconds: int, poll_interval: float = 5.0) -> bool:
    deadline = time.monotonic() + timeout_seconds
    attempt = 0
    while time.monotonic() < deadline:
        attempt += 1
        try:
            response = requests.get(health_url, timeout=10)
            if response.status_code == 200:
                data = response.json()
                if data.get('status') == 'healthy':
                    print(f'Service healthy after {attempt} attempt(s).')
                    return True
                print(f'Attempt {attempt}: status={data.get("status", "unknown")}')
            else:
                print(f'Attempt {attempt}: HTTP {response.status_code}')
        except requests.RequestException as e:
            print(f'Attempt {attempt}: connection error - {e}')

        remaining = deadline - time.monotonic()
        if remaining <= 0:
            break
        time.sleep(min(poll_interval, remaining))

    raise TimeoutError(
        f'Service at {health_url} did not become healthy within {timeout_seconds}s '
        f'after {attempt} attempt(s).'
    )

def get_shard_files(files: list, shard_index: int, total_shards: int) -> list:
    if total_shards < 1:
        raise ValueError(f'total_shards must be >= 1, got {total_shards}')
    if not (0 <= shard_index < total_shards):
        raise ValueError(
            f'shard_index must be in range [0, {total_shards - 1}], got {shard_index}'
        )
    return files[shard_index::total_shards]

from collections import defaultdict

def find_flaky_tests(runs: list) -> dict:
    test_outcomes = defaultdict(list)  # test_name -> [True, False, ...]

    for run in runs:
        for test_name, passed in run.get('results', {}).items():
            test_outcomes[test_name].append(passed)

    flaky = {}
    for test_name, outcomes in test_outcomes.items():
        if len(outcomes) < 2:
            continue  # Need at least 2 runs to determine flakiness
        if True in outcomes and False in outcomes:
            failure_rate = round(outcomes.count(False) / len(outcomes), 2)
            flaky[test_name] = failure_rate

    return flaky

import os

def audit_secrets(required_secrets: list) -> dict:
    present = []
    missing = []

    for secret in required_secrets:
        value = os.environ.get(secret, '')
        if value.strip():
            present.append(secret)
        else:
            missing.append(secret)

    if missing:
        print(f'WARNING: The following required secrets are not set: {missing}')
        print('Pipeline steps that depend on these secrets will fail.')

    return {'present': present, 'missing': missing}

def extract_failed_tests(log_output: str) -> list:
    failed = set()
    for line in log_output.splitlines():
        stripped = line.strip()
        if stripped.startswith('FAILED '):
            # Format: 'FAILED path::test - ErrorType: message'
            test_part = stripped[len('FAILED '):]
            node_id = test_part.split(' - ')[0].strip()
            if node_id:
                failed.add(node_id)
    return sorted(failed)

import json

def build_matrix_json(services: list) -> str:
    if not services:
        raise ValueError('services list must not be empty')
    matrix = {
        'include': [{'service': s} for s in services]
    }
    return json.dumps(matrix)
